SELECT DISTINCT r.*
FROM emr_record r


        AND (r.title LIKE CONCAT('%', #{q.keyword}, '%')
        OR r.content LIKE CONCAT('%', #{q.keyword}, '%')
        OR r.disease LIKE CONCAT('%', #{q.keyword}, '%'))


        AND r.disease LIKE CONCAT('%', #{q.disease}, '%')


        AND r.archive_status = #{q.archiveStatus}


        AND r.record_type = #{q.recordType}


        AND r.create_time >= #{q.beginTime}


        AND r.create_time <= #{q.endTime}



            AND EXISTS (
                SELECT 1 FROM emr_entity e
                WHERE e.record_id = r.id
                AND e.label_type = #{f.labelType}
                AND e.entity_text LIKE CONCAT('%', #{f.keyword}, '%')
            )



ORDER BY r.create_time DESC
